const response = $input.item.json;
const rawText = response.content[0].text;
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();
try {
  const article = JSON.parse(cleaned);
  return [{
    json: {
      title:           article.title,
      content:         article.content,
      excerpt:         article.excerpt,
      tags:            article.tags,
      seo_title:       article.seo_title,
      seo_description: article.seo_description,
      focus_keyword:   article.focus_keyword || article.tags[0],
      image_subject:   article.image_subject,
      affiliate_flag:  article.affiliate_flag,
    }
  }];
} catch (e) {
  throw new Error('Claude response could not be parsed as JSON. Raw response: ' + rawText.substring(0, 500));
}

const prediction = $input.item.json.predictions[0];
const base64 = prediction.bytesBase64Encoded;
const mimeType = prediction.mimeType || 'image/png';
const focusKeyword = $('PARSE ARTICLE').item.json.focus_keyword || 'featured';
const slug = focusKeyword.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/, '');
const filename = slug + '.png';
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(base64, 'base64'),
  filename,
  mimeType
);
return [{ json: { image_filename: filename }, binary: { data: binaryData } }];

const tagIds = $input.all().map(item => {
  const r = item.json;
  return r.id || (r.data && r.data.term_id) || null;
}).filter(id => id !== null && id !== undefined && id !== 0);
return [{ json: { tag_ids: tagIds } }];

